<template>
  <div id="app">
    <div class="loading-box" v-if="loading">
      <span class="loading"></span>
      <span>{{progress}}%</span>
    </div>
    <ViewPDF
      ref="myPdfComponent"
      :src="url"
      :page="currentPage"
      :rotate="rotate"
      @progress="onProgress"
      @page-loaded="onPageLoaded"
      @num-pages="onNumPages"
      @error="onPdfError"
    />
    <div class="button-group">
      <button class="button" @click="transformAngle">方向</button>
      <button class="button" @click="scaleGrow">放大</button>
      <button class="button" @click="scaleNarrow" :disabled="scale === 100">缩小</button>
      <button class="button" @click="prevPage" :disabled="currentPage === 1">上页</button>
      <button class="button" @click="nextPage" :disabled="currentPage === pageTotal">下页</button>
    </div>
    
  </div>
</template>

<script>
import ViewPDF from 'vue-pdf';
import socket from '../socket';

export default {
  mixins: [socket],
  data() {
    return {
      loading: true,
      url: 'https://mozilla.github.io/pdf.js/web/compressed.tracemonkey-pldi-09.pdf',  // '/demopdf.pdf',
      progress: 0,
      rotate: 0, // 角度
      pageTotal: 0, // 总页数
      currentPage: 1, // 当前页数
      pageRendering: false,
      scale: 100, // 放大系数
      status: 0, // 0: 准备中/结束直播，1: 开始直播，2：直播暂停
    };
  },
  created() {
  },
  mounted() {
    // window.document.body.addEventListener('touchmove', (e) => {
    //   e.preventDefault()
    // }, {
    //   passive: false
    // });
    setTimeout(() => {
      this.send();
    }, 5000);
  },
  components: {
    ViewPDF,
  },
  computed: {
  },
  methods: {
    // pdf监听事件
    onProgress(val) { // 进度
      this.progress = Math.round((val || 0) * 1000) / 10;
    },
    onPageLoaded(event) { // 当前页加载
      console.log('onPageLoaded', event);
      this.loading = false;
    },
    onNumPages(event) { // 获取总页数
      this.pageTotal = event;
    },
    onPdfError(err) {
      console.log(err);
    },
    // 上一页
    prevPage() {
      if (this.currentPage !== 1) {
        this.currentPage -= 1;
      }
    },
    
    // 下一页
    nextPage() {
      if (this.currentPage < this.pageTotal) {
        this.currentPage += 1;
      }
    },
    // 放大
    scaleGrow() {
        this.scale += 5;
        this.$refs.myPdfComponent.$el.style.width = parseInt(this.scale) + "%";
    },
    // 缩小
    scaleNarrow() {
      if (this.scale == 100) {
        return;
      }
      this.scale += -5;
      this.$refs.myPdfComponent.$el.style.width = parseInt(this.scale) + "%";
    },
    // 方向角度
    transformAngle() {
      this.rotate += 90;
      if (this.rotate === 360) {
        this.rotate = 0;
      }
    }
  },
};
</script>

